#include <bits/stdc++.h>
constexpr int N = 3e5 + 10, S = 1.1e7, SS = 2 * S;
int n, q;
int next[SS], val[SS], cnt;
struct queue {
	int head, tail;
	void push(int x) {
		if(head) {
			next[tail] = ++ cnt, val[cnt] = x; tail = cnt;
		} else {
			head = tail = ++ cnt, val[cnt] = x;
		}
		assert(cnt < SS - 100);
	}
	void pop() {head = next[head];}
	int front() {return val[head];}
	bool check() {return head == tail;}
	bool empty() {return head == 0;}
	void clear() {head = tail = 0;}
};
struct node {
	int ls, rs;
	queue fa;
	int val, exit;
	int size, rev;
}a[S];
int tot;
int id[N];
void pushup(int u) {
	a[u].size = a[a[u].ls].size + a[a[u].rs].size;
}
void setR(int u) {
	a[u].rev ^= 1;
	std::swap(a[u].ls, a[u].rs);
}
void setT(int u, int v) {
	a[u].fa.push(v);
}
void pushdown(int u) {
	if(a[u].rev) {
		setR(a[u].ls);
		setR(a[u].rs);
		a[u].rev = 0;
	}
}
int newnode() {
	int u = ++ tot;
	a[u].exit = 2;
	return u;
}
int newleaf() {
	int u = newnode();
	a[u].size = 1;
	return u;
}
int join(int x, int y) {
	int u = newnode();
	a[u].ls = x, a[u].rs = y;
	a[x].fa.push(u);
	a[y].fa.push(u);
	pushup(u);
	return u;
}
auto cut(int x) {
	pushdown(x);
	a[x].exit = 1;
	return std::make_pair(a[x].ls, a[x].rs);
}
int get_val(int u) {
	if(a[u].exit == 0) return 0;
	if(a[u].val != 0) return a[u].val;
	if(a[u].fa.empty()) return 0;
	int ans = 0;
	while(1) {
		ans = get_val(a[u].fa.front());
		if(ans) return ans;
		if(a[u].fa.check()) break;
		a[u].fa.pop();
	}
	if(a[u].exit == 1) {
		a[u].exit = 0;
		a[u].fa.pop();
		a[u].fa.clear();
	}
	return 0;
}
int newtag(int x) {
	int u = ++ tot;
	a[u].val = x;
	a[u].exit = 1;
	return u;
}
constexpr double ALPHA = 0.292;
bool too_heavy(int sx, int sy) {
	return sy < ALPHA * (sx + sy);
}
int merge(int x, int y) {
	if(!x || !y) return x + y;
	if(too_heavy(a[x].size, a[y].size)) {
		auto [u, v] = cut(x);
    	if(too_heavy(a[v].size + a[y].size, a[u].size)) {
    		auto [z, w] = cut(v);
    		return merge(merge(u, z), merge(w, y));
   		} else {
    		return merge(u, merge(v, y));
    	}
  	} else if(too_heavy(a[y].size, a[x].size)) {
		auto [u, v] = cut(y);
		if(too_heavy(a[u].size + a[x].size, a[v].size)) {
			auto [z, w] = cut(u);
			return merge(merge(x, z), merge(w, v));
		} else {
			return merge(merge(x, u), v);
		}
	} else {
		return join(x, y);
	}
}
std::pair<int, int> split(int x, int k) {
	if(!x) return {0, 0};
	if(!k) return {0, x};
	if(k == a[x].size) return {x, 0};
	auto [u, v] = cut(x);
	if(k <= a[u].size) {
		auto [w, z] = split(u, k);
		return {w, merge(z, v)};
	} else {
		auto [w, z] = split(v, k - a[u].size);
		return {merge(u, w), z};
	}
}
int find(int u, int k) {
	if(a[u].size == 1) return u;
	pushdown(u);
	if(k <= a[a[u].ls].size) return find(a[u].ls, k);
	else return find(a[u].rs, k - a[a[u].ls].size);
}
int build(int n) {
	if(n == 1) return newleaf();
	int x = build(n / 2);
	int y = build(n - n / 2);
	return join(x, y);
}
int main() {
	std::ios::sync_with_stdio(false), std::cin.tie(0);
	std::cin >> n >> q;
	int rt = build(n);
	int lastans = 0;
	for(int i = 1; i <= q; i ++) {
		int o;
		std::cin >> o;
		if(o == 1) {
			int p;
			std::cin >> p;
			p = (p + lastans - 1) % n + 1;
			auto [A, B] = split(rt, p);
			setT(A, id[i] = newtag(i));
			rt = merge(A, B);
		} else if(o == 2) {
			int p;
			std::cin >> p;
			p = (p + lastans - 1) % n + 1;
			auto [A, B] = split(rt, p);
			setR(A);
			rt = merge(A, B);
		} else if(o == 3) {
			int x;
			std::cin >> x;
			x = (x + lastans - 1) % q + 1;
			a[id[x]].exit = 0;
		} 
		int p;
		std::cin >> p;
		p = (p + lastans - 1) % n + 1;
		int u = find(rt, p);
		std::cout << (lastans = get_val(u)) << '\n';
	}
	return 0;
}

